message.content:
{
  "design_direction": "Integración mínima de Helios como cerebro central, priorizando mobile con simplicidad y claridad humana.",
  "home_explainer": {
    "section_title": "Helios, tu aliado en el expediente",
    "section_intro": "Helios analiza tus documentos laborales para darte claridad, separar lo seguro de lo estimado y sugerir pasos simples para fortalecer tu respaldo.",
    "cards": [
      {"title": "Interpreta documentos", "body": "Lee y explica en palabras sencillas lo que dicen tus papeles laborales."},
      {"title": "Separa claro de estimado", "body": "Distingue hechos confirmados de cálculos aproximados para que sepas dónde enfocarte."},
      {"title": "Fortalece tu expediente", "body": "Ordena todo y te guía en el siguiente paso para un respaldo más sólido."}
    ]
  },
  "auditar_microstate": {
    "placement": "Encima de la lista de documentos en /auditar, como un banner sutil mobile-friendly",
    "title": "Helios está trabajando",
    "body": "Mira el estado actual mientras Helios analiza y fortalece tu expediente.",
    "status_mapping": [
      {"status": "pending_dispatch", "label": "Preparando", "description": "Helios se alista para revisar tu documento."},
      {"status": "sent", "label": "Enviado", "description": "Tu documento ya está en camino a Helios."},
      {"status": "processing", "label": "Analizando", "description": "Helios está interpretando y separando lo claro de lo estimado."},
      {"status": "completed", "label": "Listo", "description": "Helios ha terminado y fortalecido tu expediente."},
      {"status": "partial", "label": "Parcial", "description": "Helios ha completado parte del análisis; revisa lo disponible."},
      {"status": "error", "label": "Problema", "description": "Algo salió mal; intenta subir de nuevo o contacta soporte."},
      {"status": "timeout", "label": "Tiempo excedido", "description": "El análisis tardó mucho; prueba otra vez."},
      {"status": "not_configured", "label": "No disponible", "description": "Helios no está listo para este tipo de documento aún."}
    ]
  },
  "remote_ready_contract": {
    "ui_rule": "Mantener UI idéntica para mock y remote, solo cambiar modo en config sin impacto visual.",
    "backend_rule": "Usar modo como flag para enrutar requests, reutilizando status y opinion existentes.",
    "mode_strategy": "Switch backend por entorno (dev/mock, prod/remote) con fallback a mock si remote falla.",
    "minimum_fields": ["engine", "mode", "status", "opinion"],
    "future_events": ["remote_success", "mode_switch", "fallback_trigger"]
  },
  "copy_principles": ["Usar lenguaje simple y humano", "Enfocarse en beneficios claros", "Evitar términos técnicos"],
  "implementation_priority": ["Agregar microestado en /auditar", "Implementar sección explicativa en home", "Preparar contrato para remote"],
  "risks_to_avoid": ["Sobrecargar la UI con elementos innecesarios", "Exponer jerga técnica en mensajes visibles", "Alterar el flujo simple existente"]
}
